import vex
from ag2.callbacks import register_message_hook

@vex.hook(priority="high")
def content_verification(message, agent_name, context):
    """Vex verification for AG2 messages"""

    verifications = {
        "brand_voice": vex_client.verify_brand_voice(message.content),
        "topic_relevance": vex_client.verify_relevance(message.content, context["topic"]),
        "safety": vex_client.verify_safety(message.content)
    }

    if not all(v["approved"] for v in verifications.values()):
        return {
            "block": True,
            "reason": "Failed verifications",
            "failed_checks": [k for k,v in verifications.items() if not v["approved"]]
        }

    return {"approved": True}

# Register globally
register_message_hook(content_verification)

FACT_SOURCES = [
    "https://api.factcheck.org/v1/claims",
    "https://api.wikipedia.org",
    "https://newsapi.org/v2"
]

@vex.verifier(name="factual_accuracy")
def verify_facts(content, claims):
    results = []
    for claim in claims:
        # Extract claims from researcher messages
        fact_check = vex_client.check_claim(
            claim=claim,
            sources=FACT_SOURCES,
            confidence_threshold=0.9
        )
        results.append(fact_check)

    return {
        "approved": all(r["verified"] for r in results),
        "confidence": sum(r["confidence"] for r in results) / len(results),
        "sources": [r["source"] for r in results]
    }

# Auto-trigger on fact-checker messages
vex_client.register_trigger("factual_accuracy", agents=["Researcher", "FactChecker"])

@vex.verifier(name="seo_compliance")
def verify_seo(content, keywords, guidelines):
    analysis = vex_client.analyze_seo(
        content=content,
        target_keywords=keywords,
        readability_target=65,
        structure_rules=guidelines
    )

    return {
        "approved": (analysis["keyword_density"] > 0.015 and 
                    analysis["readability"] > 60),
        "metrics": analysis,
        "suggestions": analysis.get("improvements", [])
    }

@vex.verifier(name="originality")
def check_originality(content):
    plagiarism_score = vex_client.check_plagiarism(content)
    return {
        "approved": plagiarism_score < 5,
        "originality_score": 100 - plagiarism_score
    }

# Composite verification for final output
vex_client.create_suite("content_final", [
    "seo_compliance",
    "originality",
    "brand_consistency"
])
